set-variable.value:
#[%dw 2.0
output application/java

---
"<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>
<title>Account Already Exists</title>

<style>
*{
margin:0;
padding:0;
box-sizing:border-box;
font-family:'Segoe UI',Arial,sans-serif;
}

body{
background:#eef3f8;
padding:30px;
}

.wrapper{
max-width:760px;
margin:auto;
background:#fff;
border-radius:18px;
overflow:hidden;
box-shadow:0 12px 35px rgba(0,0,0,.15);
}

.header{
background:linear-gradient(135deg,#b30000,#d62828,#ff5a5f);
padding:40px;
text-align:center;
color:white;
}

.logo{
font-size:36px;
font-weight:bold;
}

.tagline{
margin-top:8px;
font-size:15px;
opacity:.9;
}

.hero{
padding:35px;
text-align:center;
background:#fff7f7;
}

.hero h2{
color:#b30000;
margin-bottom:12px;
}

.hero p{
font-size:15px;
line-height:28px;
color:#555;
}

.alert{
margin:25px;
padding:20px;
background:#fdeaea;
border-left:6px solid #d62828;
border-radius:10px;
font-size:16px;
font-weight:bold;
color:#b30000;
}

.card{
margin:30px;
border:1px solid #e5e5e5;
border-radius:15px;
overflow:hidden;
}

.card-title{
background:#b30000;
color:white;
padding:18px;
font-size:20px;
font-weight:bold;
}

table{
width:100%;
border-collapse:collapse;
}

td{
padding:18px;
border-bottom:1px solid #eeeeee;
}

td:first-child{
width:38%;
background:#fafafa;
font-weight:bold;
color:#555;
}

.acc{
font-size:22px;
font-weight:bold;
color:#0056B3;
}

.status{
background:#ffe5e5;
color:#b30000;
padding:6px 18px;
border-radius:20px;
font-weight:bold;
}

.note{
margin:0 30px 30px;
padding:22px;
background:#fff9e8;
border-left:6px solid orange;
border-radius:10px;
}

.note h3{
color:#c97b00;
margin-bottom:10px;
}

.note li{
margin:10px 0;
}

.footer{
background:#002B5B;
padding:35px;
text-align:center;
color:white;
}

.footer p{
line-height:24px;
font-size:13px;
}

.support{
margin-top:18px;
padding-top:18px;
border-top:1px solid rgba(255,255,255,.2);
}
</style>

</head>

<body>

<div class='wrapper'>

<div class='header'>

<div class='logo'>
🏦 " ++ (vars.inputAttributes.bankName default "REAL BANK") ++ "
</div>

<div class='tagline'>
Safe • Secure • Trusted Banking
</div>

</div>

<div class='hero'>

<h2>
⚠ Account Already Exists
</h2>

<p>

Dear <b>" ++ upper(vars.inputPayload.FullName default "CUSTOMER") ++ "</b>,

<br><br>

Our records indicate that an account already exists with the information you provided.

</p>

</div>

<div class='alert'>

❌ " ++ (payload.message default "An account already exists with the provided customer details.") ++ "

</div>

<div class='card'>

<div class='card-title'>
📋 Existing Account Details
</div>

<table>

<tr>
<td>👤 Customer Name</td>
<td>" ++ (vars.inputPayload.FullName default "") ++ "</td>
</tr>

<tr>
<td>🏦 Bank Name</td>
<td>" ++ (vars.inputAttributes.bankName default "") ++ "</td>
</tr>

<tr>
<td>💳 Existing Account Number</td>
<td class='acc'>" ++ (payload.ACCOUNTNUMBER default "N/A") ++ "</td>
</tr>

<tr>
<td>🪪 Aadhaar Number</td>
<td>XXXX XXXX " ++ (((vars.inputAttributes.adharNumber default "") as String)[-4 to -1]) ++ "</td>
</tr>

<tr>
<td>📧 Email</td>
<td>" ++ (vars.inputPayload.email default "") ++ "</td>
</tr>

<tr>
<td>📱 Mobile Number</td>
<td>" ++ (vars.inputPayload.mobileNumber default "") ++ "</td>
</tr>

<tr>
<td>Account Status</td>
<td><span class='status'>FAILED</span></td>
</tr>

<tr>
<td>Status Code</td>
<td>" ++ (payload.statusCode default "409") ++ "</td>
</tr>

</table>

</div>

<div class='note'>

<h3>ℹ What You Can Do Next</h3>

<ul>

<li>Verify your Aadhaar Number and Email Address.</li>

<li>If you already have an account, please use your existing credentials.</li>

<li>If you believe this is incorrect, contact Customer Support.</li>

<li>Do not create duplicate accounts using the same details.</li>

</ul>

</div>

<div class='footer'>

<h3>
Thank You for Banking With Us ❤️
</h3>

<p>

Customer Care : +91 9494207062

<br>

Email : narsingbeesetti22@gmail.com

<br><br>

© 2026 Real Bank

<br>

Safe Banking | Digital Banking | Secure Transactions

</p>

<div class='support'>

This is an automated email. Please do not reply.

</div>

</div>

</div>

</body>
</html>"]
